\begin{align*} \text{Total Pieces} \equiv & (9+6) + (8+5) + (7+4) + (6+3) + (5+2) + (4+1) + (3+2\sqrt 3) + (2+2\sqrt 3) + (1+2\sqrt 3) \\
=& 15 + (13 + 9 + 9 + 9 + 7 + 5+ 5 + 4 + 3) \\
=& 15 + 70 \\
=& \boxed{85}
\end{align*}

